import {
    getCompareOptions
} from "../common/get_compare_options";
import {
    addAllDayPanelOccupation
} from "./utils/add_all_day_panel_occupation";
import {
    filterByAttributes
} from "./utils/filter_by_attributes/filter_by_attributes";
import {
    filterByIntervals
} from "./utils/filter_by_intervals/filter_by_intervals";
import {
    getFilterOptions
} from "./utils/get_filter_options/get_filter_options";
import {
    splitByGroupIndex
} from "./utils/split_by_group_index";
import {
    splitByRecurrence
} from "./utils/split_by_recurrence/split_by_recurrence";
const addDuration = appointments => appointments.map((appointment => Object.assign({}, appointment, {
    duration: appointment.endDateUTC - appointment.startDateUTC
})));
const saveDatesBeforeSplit = appointments => appointments.map((appointment => Object.assign({}, appointment, {
    datesBeforeSplit: {
        startDateUTC: appointment.startDateUTC,
        endDateUTC: appointment.endDateUTC
    }
})));
export const filterAppointments = (schedulerStore, appointments) => {
    const compareOptions = getCompareOptions(schedulerStore);
    const options = getFilterOptions(schedulerStore, compareOptions);
    const step1 = addAllDayPanelOccupation(appointments, options);
    const step2 = filterByAttributes(step1, options);
    const step3 = splitByRecurrence(step2, options);
    const step4 = filterByIntervals(step3, options);
    const step5 = addDuration(step4);
    const step6 = splitByGroupIndex(step5, options);
    const step7 = saveDatesBeforeSplit(step6);
    return step7
};
